-  // This value will make an overflow of 'thread count * NewSizeThreadIncrease' at DefNewGeneration::compute_new_size().
-  // = (max_uintx / 5) + 1, = (18446744073709551615 / 5) + 1
-  static String INVALID_VALUE_1 = "3689348814741910324";
